html,
body {
  min-height: 100%;
}

body {
  font-family: Arial, Helvetica, sans-serif;
  line-height: 1.6;
  color: #333;
}

.app-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
}

header {
  padding: 20px 0;
  border-bottom: 1px solid #eee;
  margin-bottom: 40px;
}

header h1 {
  margin-bottom: 10px;
}

nav {
  display: flex;
  gap: 20px;
}

nav a {
  text-decoration: none;
  color: #0070f3;
}

nav a:hover {
  text-decoration: underline;
}

main {
  padding-bottom: 40px;
}

footer {
  padding: 20px 0 40px;
  border-top: 1px solid #eee;
  margin-top: 40px;
}

.posts-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
  gap: 20px;
  margin-top: 20px;
}

.post-card {
  border: 1px solid #eee;
  padding: 20px;
  border-radius: 8px;
}

.post-card h2 {
  margin-bottom: 10px;
}

.post-card a {
  text-decoration: none;
  color: #333;
}

.post-card a:hover {
  color: #0070f3;
}

.comments {
  margin-top: 30px;
}

.comment {
  border: 1px solid #eee;
  padding: 15px;
  margin-bottom: 15px;
  border-radius: 8px;
}

.comment h3 {
  margin-bottom: 5px;
  font-size: 16px;
}

.comment small {
  color: #666;
}

.error-page {
  text-align: center;
  padding: 100px 20px;
}

.error-page h1 {
  margin-bottom: 20px;
  font-size: 2rem;
}

.error-page p {
  margin-bottom: 30px;
  font-size: 1.1rem;
}

button,
.button-link {
  display: inline-block;
  background: #0070f3;
  color: white;
  border: none;
  padding: 10px 20px;
  border-radius: 5px;
  cursor: pointer;
  font-size: 16px;
  text-decoration: none;
}

button:hover,
.button-link:hover {
  background: #0051a2;
  color: white;
}

article > button {
  margin-bottom: 20px;
}

ul {
  padding-left: 20px;
}

li + li {
  margin-top: 8px;
}
